var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"아직 늦지 않았습니다. 사장님.","JPN":"まだ間に合いますよ、社長。","ENG":"It's not too late, Boss.","TWN":"現在還來得及，老闆。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"절 약 올릴 계획이었다거나, 공들여 준비한 장난이었다거나...... 변명거리가 있으면 지금 말씀하세요.","JPN":"私をからかうつもりだったとか、手の込んだイタズラだったのなら……今が弁解する最後のチャンスです。","ENG":"If this was some kind of an elaborate prank... fess up while you still have the chance.","TWN":"是你故意惹我的計畫也好，是你精心準備的玩笑也罷……有什麼藉口，現在都說出來吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"솔직하게 말하면 총알 한 발로 없던 셈 치겠습니다.","JPN":"正直に白状してくれれば、銃弾一発でチャラにしてあげます。","ENG":"If you're honest with me, I'll only shoot you once.","TWN":"你老實說的話，我就只用一發子彈解決你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"자, 잠깐만요. 사랑한다니......","JPN":"ま、待ってください。愛しているだなんて……","ENG":"H-hang on. What do you mean, you love me?!","TWN":"等、等等，什麼叫你愛我啊……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"채신에 신경 써야 할 사람이 직장에서 대놓고 그런 고백을 해도 되나요?","JPN":"立場を考えてください。職場で、臆面もなくそんな告白をしていいのですか？","ENG":"You can't just go professing your love for me at the workplace!","TWN":"應該專注於經營之道的人，卻在職場上公然告白，你這樣對嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"볼품없이 멸치처럼 빼빼 마르기만 한 저한테 계속 관심을 드러내면 뒤에서 깨나 쑥덕거릴 텐데요.","JPN":"私はイワシみたいに骨と皮しかない、みすぼらしい女です。そんな私に構いすぎると、陰口を言われそうなのですが。","ENG":"I'm sure that people would talk behind your back if you kept showing interest in a bony, plain girl like me.","TWN":"如果你對毫無看頭、像小魚乾一樣瘦巴巴的我表示關心，肯定會有人在背後說三道四的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"그, 그렇다고 걱정한다는 건 아니지만요.","JPN":"べ、別に社長のことを心配をしているわけでは……","ENG":"B-but I'm not saying that worries me.","TWN":"雖、雖說我並不會擔心這種事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"모처럼 느슨하게 지낼 곳을 찾았는데 괜한 소리 나오게 하기 싫을 뿐입니다.","JPN":"せっかく見つけた安心できる場所ですから、余計なことで騒がれたくないだけです。","ENG":"I just don't want people gossiping when I finally managed to find a place to relax.","TWN":"只是我好不容易才找到一個可以悠閒度日的地方，不想讓人說閒話而已。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"아......?! 말 한마디 했다고 또 시무룩한 척 하지 마시고요!","JPN":"ちょっ……！？　この程度の一言でしょんぼりしないでください！\\nその手には乗りませんよ！","ENG":"Oh! Don't go pouting just because I said a few things!","TWN":"啊……？！不要因為我說你兩句，就裝出一副傷心的樣子啦！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"......아무튼. 정말 고백이라면 행동으로 보여 주세요.","JPN":"……とにかく、本気の告白なのでしたら、それを行動で示してください。","ENG":"Anyway... Show me your feelings through your actions if you mean it.","TWN":"……總之，如果這個告白是真的，那就用行動來證明吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"입으로 하는 키스는 아직 부끄러우니까...... 손등에.","JPN":"口でのキスはまだ恥ずかしいので……手の甲に。","ENG":"I'm too shy to have you kiss me on the lips... so you can kiss me on the hand.","TWN":"現在要接吻會有點害羞……你就親手背吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_WEDDING_NULL","text":{"KOREA":"아, 안아 들라고 한 적은 없잖아요! 뭘 좋다고 히죽거리는 겁니까?!","JPN":"だ、抱き上げてほしいとは言っていません！　何ニヤニヤしてるんですか！？","ENG":"I-I never said you could lift me up like this! What are you so giddy about?!","TWN":"啊，我沒說你可以抱我啊！誰准你嬉皮笑臉的？！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};